components.shader:
precision mediump float;
uniform sampler2D tSource;
uniform float uTime;
varying vec2 vUv;
void main() {
  vec2 center = vec2(0.5);
  vec2 p = vUv - center;
  // Mode 17: horizontal tunnel - scale depends on vertical distance
  float scale1 = 0.97 - p.y*p.y*1.6;
  float turn1 = 0.005;
  float cs = cos(turn1);
  float sn = sin(turn1);
  vec2 rotated = vec2(p.x*cs - p.y*sn, p.x*sn + p.y*cs);
  vec2 uv = rotated * (1.0/scale1) + center;
  uv.x = fract(uv.x);
  uv.y = clamp(uv.y, 0.0, 1.0);
  gl_FragColor = texture2D(tSource, uv) * 0.99;
}
